"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import {
  BarChart3Icon,
  BuildingIcon,
  CalendarIcon,
  HomeIcon,
  LayoutDashboardIcon,
  MessageSquareIcon,
  UsersIcon,
} from "lucide-react"

const navigationItems = [
  {
    title: "Dashboard",
    icon: LayoutDashboardIcon,
    url: "/dashboard",
  },
  {
    title: "Listings",
    icon: BuildingIcon,
    url: "/listings",
  },
  {
    title: "Bookings",
    icon: CalendarIcon,
    url: "/bookings",
  },
  {
    title: "Users",
    icon: UsersIcon,
    url: "/users",
  },
  {
    title: "Messages",
    icon: MessageSquareIcon,
    url: "/messages",
  },
  {
    title: "Analytics",
    icon: BarChart3Icon,
    url: "/analytics",
  },
]

export function AppSidebar() {
  const pathname = usePathname()

  return (
    <div className="bg-[#2c3e50] text-white w-48 h-screen flex flex-col">
      <div className="p-4">
        <Link href="/dashboard" className="flex items-center gap-2">
          <HomeIcon className="h-5 w-5" />
          <span className="text-lg font-bold">RENTRO</span>
        </Link>
      </div>
      <div className="px-2 flex-1">
        <div className="space-y-1">
          {navigationItems.map((item) => {
            const isActive = pathname === item.url || pathname.startsWith(`${item.url}/`)
            return (
              <div key={item.title}>
                <Link
                  href={item.url}
                  className={`flex items-center gap-2 px-3 py-2 rounded-md text-white hover:bg-slate-600 transition-colors ${
                    isActive ? "bg-slate-600" : ""
                  }`}
                >
                  <item.icon className="h-4 w-4" />
                  <span className="text-sm">{item.title}</span>
                </Link>
              </div>
            )
          })}
        </div>
      </div>
    </div>
  )
}
